import React, { useState } from 'react';
import './App.css';

function App() {
  const [file, setFile] = useState(null);
  const [extractedText, setExtractedText] = useState('');
  const [processedText, setProcessedText] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const handleFileChange = (e) => {
    const selectedFile = e.target.files[0];
    if (selectedFile) {
      setFile(selectedFile);
      setError('');
    }
  };

  const handleUpload = async (e) => {
    e.preventDefault();
    
    if (!file) {
      setError('Please select a file first');
      return;
    }

    setLoading(true);
    setError('');
    setExtractedText('');
    setProcessedText('');

    try {
      const formData = new FormData();
      formData.append('file', file);

      const response = await fetch('http://localhost:8000/ocr', {
        method: 'POST',
        body: formData,
      });

      if (!response.ok) {
        throw new Error('Failed to process file');
      }

      const data = await response.json();
      
      setExtractedText(data.extracted_text || '');
      setProcessedText(data.processed_text || '');
      
      if (data.error) {
        setError(`Processing error: ${data.error}`);
      }
    } catch (err) {
      setError(`Error: ${err.message}`);
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="container">
      <header className="header">
        <h1>AI-Assisted Exam Evaluator</h1>
        <p>Upload exam answer sheets for OCR and preprocessing</p>
      </header>

      <main className="main">
        <section className="upload-section">
          <form onSubmit={handleUpload}>
            <div className="file-input-wrapper">
              <label htmlFor="file-input" className="file-label">
                Choose Image or PDF
              </label>
              <input
                id="file-input"
                type="file"
                onChange={handleFileChange}
                accept="image/*,.pdf"
                disabled={loading}
              />
              {file && <p className="file-name">Selected: {file.name}</p>}
            </div>

            <button 
              type="submit" 
              className="upload-btn"
              disabled={loading || !file}
            >
              {loading ? 'Processing...' : 'Upload & Process'}
            </button>
          </form>

          {error && <div className="error-message">{error}</div>}
        </section>

        <section className="results-section">
          <div className="text-area-wrapper">
            <label htmlFor="extracted">Extracted Text (OCR)</label>
            <textarea
              id="extracted"
              value={extractedText}
              readOnly
              placeholder="OCR extracted text will appear here..."
            />
          </div>

          <div className="text-area-wrapper">
            <label htmlFor="processed">Preprocessed Text</label>
            <textarea
              id="processed"
              value={processedText}
              readOnly
              placeholder="Cleaned and preprocessed text will appear here..."
            />
          </div>
        </section>
      </main>

      <footer className="footer">
        <p>Phase: Input → OCR → Text Preprocessing | Ready for subjective evaluation</p>
      </footer>
    </div>
  );
}

export default App;
